class Solution { public: vector<vector<int>> merge(vector<vector<int>>& intervals) { if (intervals.empty()) return {}; sort(intervals.begin(), intervals.end(), [](const vector<int>& a, const vector<int>& b) { if (a[0] != b[0]) return a[0] < b[0]; return a[1] < b[1]; }); vector<vector<int>> merged; for (auto &iv : intervals) { if (merged.empty() || iv[0] > merged.back()[1]) { merged.push_back(iv); } else { merged.back()[1] = max(merged.back()[1], iv[1]); } } return merged; } };